  "questionProse": [
    "मर्ज सॉर्ट एल्गोरिदम की सबसे खराब स्थिति में समय जटिलता क्या है?"
  ],
  "explanationProse": [
    "मर्ज सॉर्ट हमेशा सबसे खराब स्थिति में O(n log n) जटिलता के साथ चलता है क्योंकि यह बार‑बार एरे को आधे में विभाजित करता है और सॉर्टेड उप‑एरे को मर्ज करता है।"
  ]
}
